create table eba_cust_clicks (
    id             number,
    cust_id        number,
    app_username   varchar2(255 byte),
    view_timestamp timestamp(6) with time zone,
    app_session    varchar2(255 byte)
);

alter table eba_cust_clicks add primary key ( id )
    using index enable;


